import { useCallback } from "react";

type Result = {
  name: string;
  email: string;
};


/* ===================== HELPERS ===================== */

function rand<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

function randInt(min: number, max: number) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function clean(str: string) {
  return str.toLowerCase().replace(/[^a-z0-9]/g, "");
}

/* ===================== CORE ===================== */

function buildName() {
  const first = rand(FIRST_NAMES);
  const last = rand(LAST_NAMES);

  const useMiddleInitial = Math.random() < 0.25;
  const middleInitial = useMiddleInitial
    ? ` ${String.fromCharCode(65 + randInt(0, 25))}.`
    : "";

  const useDoubleLast = Math.random() < 0.15;
  const last2 = useDoubleLast ? `-${rand(LAST_NAMES)}` : "";

  const fullName = `${first}${middleInitial} ${last}${last2}`;

  return {
    first,
    last: `${last}${last2}`,
    fullName,
  };
}

function buildEmail(first: string, last: string) {
  const sep = rand(SEPARATORS);
  const prefix = rand(PREFIXES);
  const suffix = rand(SUFFIXES);
  const domain = rand(DOMAINS);
  const word = rand(RANDOM_WORDS);

  const f = clean(first);
  const l = clean(last);

  const fi = f.charAt(0);
  const li = l.charAt(0);

  const year = randInt(1975, 2012);
  const num = randInt(1, 9999);

  const patterns = [
    `${f}${sep}${l}`,
    `${fi}${sep}${l}`,
    `${f}${sep}${li}`,
    `${l}${sep}${f}`,
    `${f}${sep}${l}${num}`,
    `${f}${sep}${year}`,
    `${l}${sep}${year}`,
    `${prefix}${prefix ? sep : ""}${f}${sep}${l}`,
    `${f}${sep}${l}${sep}${suffix}`,
    `${word}${sep}${f}${sep}${l}`,
    `${word}${sep}${l}${num}`,
    `${f}${num}`,
    `${l}${num}`,
    `${fi}${l}${num}`,
    `${f}${li}${num}`,
    `${prefix}${prefix ? sep : ""}${word}${sep}${num}`,
  ];

  const local = rand(patterns)
    .replace(/^\W+|\W+$/g, "")
    .replace(/\.{2,}/g, ".")
    .replace(/_{2,}/g, "_")
    .replace(/-{2,}/g, "-");

  return `${local}@${domain}`;
}

/* ===================== HOOK ===================== */

export function useNameEmailGenerator() {
  const generate = useCallback((): Result => {
    const { first, last, fullName } = buildName();
    const email = buildEmail(first, last);

    return {
      name: fullName,
      email,
    };
  }, []);

  const generateBatch = useCallback((count: number): Result[] => {
    const out: Result[] = [];
    const seen = new Set<string>();

    let attempts = 0;
    const maxAttempts = count * 20;

    while (out.length < count && attempts < maxAttempts) {
      attempts++;
      const item = generate();
      const key = item.name + item.email;

      if (!seen.has(key)) {
        seen.add(key);
        out.push(item);
      }
    }

    return out;
  }, [generate]);

  return {
    generate,
    generateBatch,
  };
}
