// src/hooks/useNameEmailGenerator.ts
import React from "react";
import {  useNameEmailGenerator } from "../../components/ppm/forms/randomuser";


const CryptPage = () => {
  const { generate, generateBatch } = useNameEmailGenerator();

  const [single, setSingle] = React.useState(() => generate());
  const [batch, setBatch] = React.useState(() => generateBatch(50));

  return (
    <main style={{ padding: 40, fontFamily: "Arial" }}>
      <h1>Super Generator</h1>

      <h2>Single</h2>
      <p><strong>Name:</strong> {single.name}</p>
      <p><strong>Email:</strong> {single.email}</p>

      <button onClick={() => setSingle(generate())}>
        Generate One
      </button>

      <hr style={{ margin: "30px 0" }} />

      <h2>Batch</h2>

      <button onClick={() => setBatch(generateBatch(50))}>
        Generate 50
      </button>

      <div style={{ marginTop: 20 }}>
        {batch.map((item, i) => (
          <div key={i}>
            {item.name} — {item.email}
          </div>
        ))}
      </div>
    </main>
  );
};

export default CryptPage;